mapper.insert:
MERGE INTO BC_SPORTS_BI_GOODS_OLDNEW target USING (
SELECT #{item.brand} AS brand, #{item.articleNo} AS article_no, #{item.season} AS season, #{item.category} AS category, #{item.createBy} AS create_by, #{item.updateBy} AS update_by FROM dual
) source ON (target.brand = source.brand AND target.article_no = source.article_no AND target.season = source.season AND target.deleted = 0) WHEN MATCHED THEN UPDATE SET target.category = source.category, target.update_time = SYSTIMESTAMP, target.update_by = source.update_by WHEN NOT MATCHED THEN INSERT (brand, article_no, season, category, create_time, update_time, create_by, update_by, deleted) VALUES (source.brand, source.article_no, source.season, source.category, SYSTIMESTAMP, SYSTIMESTAMP, source.create_by, source.update_by, 0)
